```sql
CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  customer_id INTEGER NOT NULL,
  total_cents INTEGER NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT NOW()
);

CREATE TABLE order_audit (
  id SERIAL PRIMARY KEY,
  order_id INTEGER NOT NULL,
  changed_at TIMESTAMP NOT NULL DEFAULT NOW(),
  old_total_cents INTEGER,
  new_total_cents INTEGER
);

CREATE OR REPLACE FUNCTION log_order_update() RETURNS trigger AS $$
BEGIN
  IF NEW.total_cents <> OLD.total_cents THEN
    INSERT INTO orders (order_id, changed_at, old_total_cents, new_total_cents)
    VALUES (OLD.id, NOW(), OLD.total_cents, NEW.total_cents);
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER orders_update_trigger
AFTER UPDATE ON orders
FOR EACH ROW
EXECUTE PROCEDURE log_order_update();
```

